from typing import Optional, List
from dataclasses import dataclass, field


class ValidationError(ValueError):
    """Raised when user data fails validation."""
    pass


class User:
    """Represents a single user with validation and update capabilities."""

    MIN_AGE = 1
    MAX_AGE = 149

    def __init__(self, user_id: int, name: str, email: str, age: int):
        # Validate before assigning so we never create an invalid User
        self._validate_name(name)
        self._validate_email(email)
        self._validate_age(age)

        self.id = user_id
        self.name = name
        self.email = email
        self.age = age

    # ---------- Validation (static: no instance state needed) ----------
    @staticmethod
    def _validate_name(name: str) -> None:
        if not isinstance(name, str) or not name.strip():
            raise ValidationError("Name must be a non-empty string")

    @staticmethod
    def _validate_email(email: str) -> None:
        if not isinstance(email, str) or '@' not in email:
            raise ValidationError(f"Invalid email: {email!r}")
        domain = email.split('@')[1]
        if '.' not in domain:
            raise ValidationError(f"Invalid email domain: {email!r}")

    @staticmethod
    def _validate_age(age: int) -> None:
        if not isinstance(age, int) or not (User.MIN_AGE <= age <= User.MAX_AGE):
            raise ValidationError(
                f"Age must be an int between {User.MIN_AGE} and {User.MAX_AGE}"
            )

    # ---------- Behavior ----------
    def update(self, name: Optional[str] = None,
               email: Optional[str] = None,
               age: Optional[int] = None) -> "User":
        """Update provided fields after validating them."""
        if name is not None:
            self._validate_name(name)
            self.name = name
        if email is not None:
            self._validate_email(email)
            self.email = email
        if age is not None:
            self._validate_age(age)
            self.age = age
        return self

    def to_dict(self) -> dict:
        """Serialize for APIs/storage — keeps backward compatibility."""
        return {'id': self.id, 'name': self.name,
                'email': self.email, 'age': self.age}

    def __repr__(self) -> str:
        return (f"User(id={self.id}, name={self.name!r}, "
                f"email={self.email!r}, age={self.age})")

    def __eq__(self, other) -> bool:
        return isinstance(other, User) and self.id == other.id


class UserRepository:
    """Manages a collection of Users (CRUD operations)."""

    def __init__(self):
        self._users: dict[int, User] = {}  # dict gives O(1) lookup/delete
        self._next_id = 1

    def create(self, name: str, email: str, age: int) -> User:
        user = User(self._next_id, name, email, age)
        self._users[user.id] = user
        self._next_id += 1
        return user

    def get(self, user_id: int) -> Optional[User]:
        return self._users.get(user_id)

    def update(self, user_id: int, **fields) -> Optional[User]:
        user = self.get(user_id)
        if user is None:
            return None
        return user.update(**fields)

    def delete(self, user_id: int) -> bool:
        """Returns True if a user was removed, False otherwise."""
        return self._users.pop(user_id, None) is not None

    def all(self) -> List[User]:
        return list(self._users.values())

    def __len__(self) -> int:
        return len(self._users)

    def __contains__(self, user_id: int) -> bool:
        return user_id in self._users


# ---------- Example usage ----------
if __name__ == "__main__":
    repo = UserRepository()

    alice = repo.create("Alice", "alice@example.com", 30)
    bob = repo.create("Bob", "bob@example.com", 25)
    print(f"Created: {alice}")

    repo.update(alice.id, age=31, email="alice@newdomain.com")
    print(f"Updated: {repo.get(alice.id)}")

    repo.delete(bob.id)
    print(f"Remaining users: {len(repo)}")

    # Validation demo
    try:
        repo.create("Eve", "not-an-email", 40)
    except ValidationError as e:
        print(f"Caught expected error: {e}")
